@Service
class OAuthStateService {

    private static final SecureRandom SECURE_RANDOM = new SecureRandom();
    private static final int STATE_LENGTH_BYTES = 32;

    /**
     * Generates a cryptographically secure random state parameter
     * to protect against CSRF attacks during the OAuth flow.
     */
    public String generateState() {
        byte[] stateBytes = new byte[STATE_LENGTH_BYTES];
        SECURE_RANDOM.nextBytes(stateBytes);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(stateBytes);
    }

    /**
     * Stores the state parameter in the user's session for later validation.
     */
    public void storeState(HttpSession session, String state) {
        session.setAttribute("oauth_state", state);
    }

    /**
     * Validates the returned state parameter against the one stored in the session.
     * This is critical for CSRF protection in the OAuth 2.0 flow.
     */
    public boolean validateState(HttpSession session, String returnedState) {
        if (returnedState == null || returnedState.isBlank()) {
            return false;
        }
        String storedState = (String) session.getAttribute("oauth_state");
        // Remove the state from session after validation (one-time use)
        session.removeAttribute("oauth_state");

        if (storedState == null || storedState.isBlank()) {
            return false;
        }

        // Use constant-time comparison to prevent timing attacks
        return constantTimeEquals(storedState, returnedState);
    }

    /**
     * Constant-time string comparison to prevent timing side-channel attacks.
     */
    private boolean constantTimeEquals(String a, String b) {
        if (a.length() != b.length()) {
            return false;
        }
        int result = 0;
        for (int i = 0; i < a.length(); i++) {
            result |= a.charAt(i) ^ b.charAt(i);
        }
        return result == 0;
    }
}

